arguments.command:
cd /tmp/sv-4e5accb19c0e40788e7ac10e60038701/moderate-msbuild-properties && dotnet package list --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract_packages(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = extract_packages(baseline)
a = extract_packages(after)

changes = []
unchanged = []
for key in sorted(set(b) | set(a)):
    proj, pkg = key
    bv = b.get(key)
    av = a.get(key)
    if bv == av:
        unchanged.append((proj, pkg, av))
    else:
        changes.append((proj, pkg, bv, av))

if changes:
    print('CHANGES:')
    for proj, pkg, bv, av in changes:
        print(f'  {proj} | {pkg} | {bv} -> {av}')
else:
    print('NO CHANGES - conversion is fully version-neutral')

print()
print('UNCHANGED:')
for proj, pkg, v in unchanged:
    print(f'  {proj} | {pkg} | {v}')
"

